public TreeNode buildTree(int[] inorder, int[] postorder) {
    return buildTreeHelper(inorder, postorder, 0, inorder.length - 1, 
                          0, postorder.length - 1);
}

private TreeNode buildTreeHelper(int[] inorder, int[] postorder, 
                                int inStart, int inEnd, 
                                int postStart, int postEnd) {
    if (inStart > inEnd || postStart > postEnd) {
        return null;
    }

    TreeNode root = new TreeNode(postorder[postEnd]);

    int rootIndex = inStart;
    for (int i = inStart; i <= inEnd; i++) {
        if (inorder[i] == postorder[postEnd]) {
            rootIndex = i;
            break;
        }
    }

    int leftSubtreeSize = rootIndex - inStart;

    root.left = buildTreeHelper(inorder, postorder, 
                               inStart, rootIndex - 1, 
                               postStart, postStart + leftSubtreeSize - 1);

    root.right = buildTreeHelper(inorder, postorder, 
                                rootIndex + 1, inEnd, 
                                postStart + leftSubtreeSize, postEnd - 1);

    return root;
}
